import { Fade } from "@material-ui/core";
import React, { ReactNode, useEffect, useState } from "react";


export default ({ children, title = "" }: {
  children: ReactNode,
  title?: string
}) => {
  const [show, setShow] = useState(false);

  useEffect(() => { setShow(true) }, [])

  return (
    <Fade in={show}>
      <div>
        {title &&
          <div style={{
            background: "linear-gradient(90deg, rgba(255,255,255,1) 0%, rgba(0,212,255,0) 29%)",
            padding: 20,
            paddingTop: 10,
            paddingBottom: 5,
            borderTopLeftRadius: 10,
            color: "#6060ca",
            fontWeight: "bold",
            marginLeft: 20,
            fontSize: 20,

          }}>
            <div style={{
              borderLeft: "10px solid #e4e4f1",
              paddingLeft: 20
            }}>
              {title}
            </div>
          </div>
        }

        <div style={{ display: "flex" }}>
          <div style={{ width: 20 }}>
            <div
              style={{
                width: 0,
                height: 0,
                borderTop: "10px solid transparent",
                borderBottom: "10px solid transparent",
                borderRight: "20px solid white",
                // boxShadow: "rgba(0, 0, 0, 0.16) 0px 1px 4px",
                marginTop: 20,
                zIndex: 2
              }}
            />
          </div>
          <div style={{
            backgroundColor: "rgba(255,255,255, 0.8)",
            padding: 20,
            // boxShadow: "rgba(0, 0, 0, 0.16) 0px 1px 4px",
            borderRadius: 10,
            borderTopLeftRadius: title ? 0 : 10,
            zIndex: 1
          }}>
            <div>
              {children}
            </div>
          </div>
        </div>
      </div>
    </Fade >
  )
}