export const CHANGE_ACTIVE_TAG = "CHANGE_ACTIVE_TAG";
export const CLOSE_LEFT_MENU = "CLOSE_LEFT_MENU";
export const OPEN_LEFT_MENU = "OPEN_LEFT_MENU";

export type ChangeActiveTag = ReturnType<typeof changeActiveTag>;
export const changeActiveTag = (tag: string) => {
  return {
    type: CHANGE_ACTIVE_TAG,
    payload: {
      activeTag: tag
    }
  }
}


export type CloseLeftMenu = ReturnType<typeof closeLeftMenu>;
export const closeLeftMenu = () => {
  return {
    type: CLOSE_LEFT_MENU
  }
}

export type OpenLeftMenu = ReturnType<typeof openLeftMenu>;
export const openLeftMenu = () => {
  return {
    type: OPEN_LEFT_MENU
  }
}