import React, { useEffect, useState } from "react";
import Circular from "./Circular";
import my_avatar from "../../assets/images/my_picture.jpg";
import Spacer from "../Spacer";
import { Button } from "@material-ui/core";
import { useHistory } from "react-router-dom";
import navigations from "../../constants/navigations";
import { useDispatch, useSelector } from "react-redux";
import { TRootState } from "../../redux/models/root.state";
import { TAppState } from "../../redux/models/app.state";
import routeKeys from "../../constants/routeKeys";
import MenuIcon from "@material-ui/icons/Menu";
import "./LeftMenu.scss";
import config from "../../constants/config";
import { closeLeftMenu, openLeftMenu } from "../../redux/actions/app.actions";
import Zoom from '@material-ui/core/Zoom';
import useIsMobile from "../../hooks/useIsMobile";
import Fade from '@material-ui/core/Fade';

const CustomButton = ({ routeKey, navigationPath, title }:
  {
    routeKey: string,
    navigationPath: string,
    title: string
  }
) => {
  const history = useHistory();
  const dispatch = useDispatch();
  const { isMobile } = useIsMobile();
  const { activeTag } = useSelector<TRootState, TAppState>(state => state.app);
  const navigate = (navigationPath: string) => () => { history.push(navigationPath) };
  const activeClassname = activeTag === routeKey ? " active" : "";

  return (
    <Button className={"menu-button" + activeClassname}
      onClick={() => {
        navigate(navigationPath)()
        if (isMobile) {
          dispatch(closeLeftMenu());
        }
      }}>{title}
    </Button>
  )
}


export default () => {
  const dispatch = useDispatch();
  const { leftMenuIsOpen } = useSelector<TRootState, TAppState>(state => state.app);
  const [delayedLeftMenuOpen, setDelayedLeftMenuOpen] = useState(leftMenuIsOpen);

  useEffect(
    () => {
      if (leftMenuIsOpen) {
        setTimeout(() => setDelayedLeftMenuOpen(leftMenuIsOpen), 200)
      } else {
        setDelayedLeftMenuOpen(false);
      }
    }
    , [leftMenuIsOpen])


  const handleMenuTogglerClick = () => {
    if (leftMenuIsOpen) {
      dispatch(closeLeftMenu());
    }
    else {
      dispatch(openLeftMenu());
    }
  }





  return (
    <div className="left-menu"
      style={{
        width: leftMenuIsOpen ? config.leftMenuWidth : config.collapsedMenuWidth
      }}
    >
      <div className="menu-icon-row">
        <Button className="no-min-width" onClick={handleMenuTogglerClick}>
          <MenuIcon />
        </Button>
      </div>
      <div className="container">


        <Spacer />
        <Spacer />
        <Zoom in={leftMenuIsOpen} enter={true}>

          <div className={"avatar-row"}>
            <Circular height={150}>
              <img src={my_avatar} />
            </Circular>
          </div>
        </Zoom>
        <Spacer />
        <Spacer />
        {delayedLeftMenuOpen &&
          <Fade in={delayedLeftMenuOpen}>
            <div>
              <div className="name-row">
                Ching-Cheong Lee
            </div>
              <Spacer height={10} />
              <div className="title-row" >
                <span className="software-engineer">Software Engineering</span> in Hong Kong
             </div>
              <Spacer />


              <div className="left-menu-buttons">
                <CustomButton navigationPath={navigations.ABOUT} title={"ABOUT"} routeKey={routeKeys.about} />
                <CustomButton navigationPath={navigations.SKILLS} title={"SKILLS"} routeKey={routeKeys.skills} />
                <CustomButton navigationPath={navigations.PORTFOLIO} title={"PORTFOLIO"} routeKey={routeKeys.portfolio} />
                <CustomButton navigationPath={navigations.EXPERIENCE} title={"EXPERIENCE"} routeKey={routeKeys.experience} />
                <CustomButton navigationPath={navigations.BLOG} title={"BLOG"} routeKey={routeKeys.blog} />
                <CustomButton navigationPath={navigations.CONTACT} title={"CONTACT"} routeKey={routeKeys.contact} />
              </div>
            </div>
          </Fade>
        }
      </div>
    </div >
  )
}