import { useEffect, useState } from "react";

export default () => {
  const [isMobile, setIsMobile] = useState(true);

  useEffect(
    () => {
      if (/Android|webOS|iPhone|iPad|Mac|Macintosh|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent)) {
        setIsMobile(true);
      }
      else {
        setIsMobile(false);
      }
    }, []);

  return { isMobile };
}